#include <stdlib.h>

long long fib(int n) {
    long long a = 0, b = 1, t;
    for (int i = 0; i < n; i++) {
        t = a;
        a = b;
        b = t + b;
    }
    return a;
}

int main(int argc, char **argv) {
    if (argc < 2) return 1;
    int n = atoi(argv[1]);
    printf("%lld\n", fib(n));
    return 0;
}

